#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, M; scanf("%lld %lld", &N, &M);
        long long q = M / N;
        long long lower = q * N;
        if(lower < N) lower = -1; // invalid
        long long upper = (q + (M % N != 0)) * N;
        long long ans = llabs(M - upper);
        if(lower != -1) ans = ans < llabs(M - lower) ? ans : llabs(M - lower);
        printf("%lld\n", ans);
    }
    return 0;
}

