#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); M = int(next(it))
        q = M // N
        lower = q * N
        if lower < N:
            lower = None
        upper = (q + (1 if M % N else 0)) * N
        ans = abs(M - upper)
        if lower is not None:
            ans = min(ans, abs(M - lower))
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

